// Estrai dati grezzi dall'email ricevuta via Gmail OAuth
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // --- FROM ---
  let from = '';
  if (typeof d.from === 'string') {
    from = d.from;
  } else if (d.from?.text) {
    from = d.from.text;
  } else if (d.from?.value?.[0]?.address) {
    from = d.from.value[0].address;
  }
  if (!from && d.payload?.headers) {
    const h = d.payload.headers.find(h => h.name?.toLowerCase() === 'from');
    if (h) from = h.value;
  }
  from = String(from || 'sconosciuto');

  // --- TO ---
  let to = '';
  if (typeof d.to === 'string') {
    to = d.to;
  } else if (d.to?.text) {
    to = d.to.text;
  }

  // --- SUBJECT ---
  let subject = '';
  if (typeof d.subject === 'string') {
    subject = d.subject;
  } else if (d.payload?.headers) {
    const h = d.payload.headers.find(h => h.name?.toLowerCase() === 'subject');
    if (h) subject = h.value;
  }
  subject = subject || 'Senza oggetto';

  // --- DATE ---
  let emailDate = '';
  if (d.date) emailDate = d.date;
  if (d.internalDate) emailDate = new Date(parseInt(d.internalDate)).toISOString();

  // --- MESSAGE-ID ---
  let messageId = d.messageId || d.id || '';

  // --- BODY ---
  let body = '';
  if (d.snippet) body = d.snippet;
  if (d.text) body = d.text;
  if (d.textPlain) body = d.textPlain;
  if (d.payload?.body?.data) {
    try { body = Buffer.from(d.payload.body.data, 'base64url').toString('utf-8'); } catch(e) {}
  }
  if (d.payload?.parts) {
    for (const part of d.payload.parts) {
      if (part.mimeType === 'text/plain' && part.body?.data) {
        try { body = Buffer.from(part.body.data, 'base64url').toString('utf-8'); } catch(e) {}
        break;
      }
    }
  }

  results.push({
    json: {
      email_from: from,
      email_to: to,
      email_subject: subject,
      email_body: String(body).substring(0, 8000),
      email_date: emailDate,
      email_message_id: messageId
    }
  });
}

return results;

