// Combina i dati email originali con l'output AI
const emailData = $('Parsa Email').first().json;
const aiRaw = $input.first().json;

// DEBUG: logga la struttura esatta della risposta AI per diagnostica
console.log('[DEBUG] AI raw response keys:', Object.keys(aiRaw));
console.log('[DEBUG] AI raw response:', JSON.stringify(aiRaw).substring(0, 500));

// Estrai il testo JSON dalla risposta AI
// Supporta tutti i formati: OpenAI diretto, n8n wrapper, Anthropic
let aiText = '';
let aiData = null;

// 1. Se l'output è già un oggetto con i campi AI (il nodo l'ha già parsato)
if (aiRaw.action && (aiRaw.ai_title || aiRaw.ai_description)) {
  aiData = aiRaw;
}
// 2. OpenAI API raw: choices[0].message.content
else if (aiRaw.choices?.[0]?.message?.content) {
  aiText = aiRaw.choices[0].message.content;
}
// 3. OpenAI n8n node: message.content come stringa
else if (typeof aiRaw.message?.content === 'string') {
  aiText = aiRaw.message.content;
}
// 4. n8n OpenAI node output diretto: content come stringa  
else if (typeof aiRaw.content === 'string') {
  aiText = aiRaw.content;
}
// 5. Campo text diretto
else if (typeof aiRaw.text === 'string') {
  aiText = aiRaw.text;
}
// 6. Campo output diretto (alcuni nodi n8n)
else if (typeof aiRaw.output === 'string') {
  aiText = aiRaw.output;
}
// 7. Campo response diretto
else if (typeof aiRaw.response === 'string') {
  aiText = aiRaw.response;
}
// 8. Anthropic: message.content[0].text
else if (aiRaw.message?.content?.[0]?.text) {
  aiText = aiRaw.message.content[0].text;
}
// 9. Fallback: serializza tutto
else {
  aiText = JSON.stringify(aiRaw);
}

// Se non abbiamo già aiData, parsa il testo
if (!aiData && aiText) {
  // Pulisci eventuali markdown code blocks
  aiText = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  try {
    aiData = JSON.parse(aiText);
  } catch (e) {
    console.error('[DEBUG] JSON parse failed:', e.message, 'Text:', aiText.substring(0, 200));
    // Fallback: crea un payload minimo per non perdere l'email
    aiData = {
      action: 'new_request',
      ai_title: emailData.email_subject,
      ai_description: `Parsing AI fallito — email da verificare manualmente.\n\nRisposta AI raw: ${aiText.substring(0, 300)}`,
      ai_priority: 'MEDIUM',
      ai_summary: `Parsing automatico fallito per email da ${emailData.email_from}. Errore: ${e.message}`,
      ai_confidence: 0.1,
      ai_items: [],
      ai_tags: ['parsing-fallito', 'verifica-manuale']
    };
  }
}

console.log('[DEBUG] Parsed AI data action:', aiData?.action, 'title:', aiData?.ai_title);

// Merge: dati email grezzi + analisi AI
const payload = {
  // Email originale
  email_from: emailData.email_from,
  email_to: emailData.email_to || undefined,
  email_subject: emailData.email_subject,
  email_body: emailData.email_body,
  email_date: emailData.email_date || undefined,
  email_message_id: emailData.email_message_id || undefined,

  // AI analysis
  action: aiData.action || 'new_request',
  ai_matched_request_code: aiData.ai_matched_request_code || undefined,
  ai_matched_external_ref: aiData.ai_matched_external_ref || undefined,
  ai_vendor_code: aiData.ai_vendor_code || undefined,
  ai_vendor_name: aiData.ai_vendor_name || undefined,
  ai_title: aiData.ai_title || undefined,
  ai_description: aiData.ai_description || undefined,
  ai_priority: aiData.ai_priority || undefined,
  ai_category: aiData.ai_category || undefined,
  ai_department: aiData.ai_department || undefined,
  ai_needed_by: aiData.ai_needed_by || undefined,
  ai_estimated_amount: typeof aiData.ai_estimated_amount === 'number' ? aiData.ai_estimated_amount : undefined,
  ai_actual_amount: typeof aiData.ai_actual_amount === 'number' ? aiData.ai_actual_amount : undefined,
  ai_currency: aiData.ai_currency || 'EUR',
  ai_status_update: aiData.ai_status_update || undefined,
  ai_tracking_number: aiData.ai_tracking_number || undefined,
  ai_external_ref: aiData.ai_external_ref || undefined,
  ai_external_url: aiData.ai_external_url || undefined,
  ai_expected_delivery: aiData.ai_expected_delivery || undefined,
  ai_items: Array.isArray(aiData.ai_items) ? aiData.ai_items : [],
  ai_summary: aiData.ai_summary || undefined,
  ai_confidence: typeof aiData.ai_confidence === 'number' ? aiData.ai_confidence : 0.5,
  ai_tags: Array.isArray(aiData.ai_tags) ? aiData.ai_tags : [],
  attachments: []
};

console.log('[DEBUG] Final payload action:', payload.action, 'title:', payload.ai_title, 'items:', payload.ai_items.length);

return [{ json: payload }];

